'use client'

import { FileText, TableProperties } from "lucide-react";
import * as XLSX from "xlsx";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

interface Props {
  results: any[];
  voters: any[];
  totalVotes: number;
}

export default function ReportButtons({ results, voters, totalVotes }: Props) {

  const exportToExcel = () => {
    const excelData = voters.map(v => ({
      "Nombre Completo": v.fullName,
      "Documento": v.documentId,
      "Estado del Voto": v.hasVoted ? "VOTÓ" : "NO VOTÓ",
      "Fecha de Registro": new Date(v.createdAt).toLocaleDateString()
    }));
    const worksheet = XLSX.utils.json_to_sheet(excelData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Registro de Votantes");
    XLSX.writeFile(workbook, `Lista_Votantes_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const exportToPDF = () => {
    const doc = new jsPDF();
    
    const membrete = "data:image/png;base64,";

    
    doc.addImage(membrete, "PNG", 10, 5, 190, 40);
    
    doc.setFontSize(18);
    doc.text("ACTA DE ESCRUTINIO OFICIAL", 105, 60, { align: "center" });
    
    doc.setFontSize(11);
    doc.text(`Fecha de Emisión: ${new Date().toLocaleDateString()}`, 14, 75);
    doc.text(`Total de Votos Registrados: ${totalVotes}`, 14, 82);

    const texto = "De conformidad con el proceso de votación realizado, con el fin de elegir al vocero de los contratista ante el Comité de Convivencia Laboral de ASMETA, se dejan consignados los resultados obtenidos.\n\nUna vez efectuado el conteo de los votos válidamente emitidos, se establece que el candidato con mayor número de votos será designado Representante Principal, y el segundo lugar será designado Representante Suplente.";
    
    doc.text(texto, 14, 95, { maxWidth: 180, align: "justify" });

    
    autoTable(doc, {
      head: [["Posición", "Candidato", "Nº de Documento", "Votos"]],
      body: results.map((c, index) => [
        `#${index + 1}`,
        c.fullName,
        c.position || "N/A", 
        c._count.votes.toString()
      ]),
      startY: 140,
      theme: 'striped',
      headStyles: { fillColor: [31, 107, 58] }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 40;
    doc.line(30, finalY, 80, finalY);
    doc.text("Firma Director Ejecutivo", 35, finalY + 8);
    doc.line(130, finalY, 180, finalY);
    doc.text("Firma del Testigo", 135, finalY + 8);

    doc.save(`Acta_Escrutinio_${new Date().toISOString().split('T')[0]}.pdf`);
  };

  return (
    <div className="flex gap-4">
      <button onClick={exportToExcel} className="flex items-center bg-wp-primary text-white px-4 py-2 rounded border border-black font-bold">
        <TableProperties className="h-4 w-4 mr-2" /> Excel
      </button>
      <button onClick={exportToPDF} className="flex items-center bg-wp-primary text-white px-4 py-2 rounded border border-black font-bold">
        <FileText className="h-4 w-4 mr-2" /> PDF
      </button>
    </div>
  );
}